            //
            aOrbiterC = (((aWandererF + RotL64(aScatter, 51U)) + RotL64(aCarry, 57U)) + 0x27F477CEF5BF26CBULL) + aPhaseFOrbiterAssignSaltB[(((31U - aIndex) + 7U)) & S_SALT1];
