            aOrbiterD = (aWandererE + RotL64(aPrevious, 3U)) + 0xE8C29148EEECC135ULL;
            aOrbiterK = ((aWandererA + RotL64(aIngress, 57U)) + RotL64(aCarry, 27U)) + 0xFDF6275D70F3F972ULL;
            aOrbiterH = (aWandererC + RotL64(aCross, 21U)) + 0xD5AB1116ABE39EDCULL;
            //
            aOrbiterC = ((aOrbiterC + aOrbiterI) + 0x37F51ACF81FD0EB9ULL) + aPhaseFOrbiterUpdateSaltF[((aIndex + 10U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterC) ^ 0xF06424E2346C3737ULL;
