            //
            aOrbiterJ = (aOrbiterJ + aOrbiterC) + 0x9870E7DD150DF72DULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterJ) ^ 0x63FA431D05EBCC53ULL;
            aOrbiterD = RotL64((aOrbiterD * 0xF11C768982E422FDULL), 21U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterK) + 0xE81284B96A133D63ULL) + aPhaseFOrbiterUpdateSaltB[((aIndex + 21U)) & S_SALT1];
