            //
            aWandererF = aWandererF ^ (((RotL64(aScatter, 27U) + aOrbiterK) + RotL64(aOrbiterC, 60U)) + aPhaseFWandererUpdateSaltA[(((31U - aIndex) + 23U)) & S_SALT1]);
            aWandererA = aWandererA + ((RotL64(aPrevious, 47U) + RotL64(aOrbiterD, 51U)) + aOrbiterI);
