            aOrbiterF = (aOrbiterF ^ aOrbiterD) ^ 0xC0E5154AFD36041FULL;
            aOrbiterF = RotL64((aOrbiterF * 0x9B33685858C0B431ULL), 29U);
            //
            aIngress = aOrbiterE ^ RotL64(aOrbiterF, 4U);
            aIngress = aIngress + (aOrbiterJ ^ RotL64(aOrbiterH, 13U));
            aIngress = aIngress + (RotL64(aOrbiterA, 47U) ^ aOrbiterI);
            aIngress = aIngress + (RotL64(aOrbiterD, 51U) ^ aOrbiterG);
            aIngress = aIngress + RotL64(aOrbiterK, 23U);
            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererC = aWandererC ^ ((RotL64(aIngress, 58U) + aOrbiterE) + RotL64(aOrbiterG, 47U));
            aWandererB = aWandererB + (((RotL64(aCross, 41U) + aOrbiterD) + RotL64(aOrbiterH, 12U)) + aPhaseFWandererUpdateSaltA[((aIndex + 15U)) & S_SALT1]);
            aWandererE = aWandererE ^ ((RotL64(aPrevious, 5U) + aOrbiterD) + RotL64(aOrbiterA, 35U));
            aWandererG = aWandererG + ((RotL64(aScatter, 21U) + RotL64(aOrbiterE, 39U)) + aOrbiterA);
