            aWandererA = aWandererA + (((RotL64(aIngress, 29U) + RotL64(aOrbiterG, 57U)) + aOrbiterK) + RotL64(aCarry, 13U));
            aWandererD = aWandererD ^ ((RotL64(aScatter, 47U) + aOrbiterA) + RotL64(aOrbiterI, 27U));
