            aIngress = (RotL64(aWorkLaneC[((aIndex + 28290U)) & S_BLOCK1], 39U) ^ RotL64(aWorkLaneA[((aIndex + 30285U)) & S_BLOCK1], 4U));
            aIngress ^= (RotL64(aInvestLaneF[((aIndex + 31730U)) & S_BLOCK1], 27U) ^ RotL64(aWaterLaneB[((S_BLOCK1 - aIndex + 32447U)) & S_BLOCK1], 57U));
