            aOrbiterB = (((aWandererF + RotL64(aCross, 53U)) + RotL64(aCarry, 3U)) + 0x41835EF0361DEB4BULL) + aPhaseDOrbiterAssignSaltE[(((31U - aIndex) + 21U)) & S_SALT1];
