            aOrbiterK = (aWandererK + RotL64(aCross, 29U)) + 0xF2FD23EDB796DD9DULL;
            aOrbiterE = ((aWandererJ + RotL64(aPrevious, 5U)) + RotL64(aCarry, 43U)) + 0x65CC5285DE0F3CB0ULL;
            aOrbiterF = ((aWandererD + RotL64(aScatter, 23U)) + 0xD3E9F0D4CC7F1544ULL) + aPhaseDOrbiterAssignSaltD[((aIndex + 27U)) & S_SALT1];
