            //
            aOrbiterC = ((aOrbiterC + aOrbiterG) + 0xE7220B6E43997B13ULL) + aPhaseDOrbiterUpdateSaltA[((aIndex + 23U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterC) ^ 0x2D2E4D5253363BCCULL;
            aOrbiterD = RotL64((aOrbiterD * 0x4E9502455EF6EB49ULL), 53U);
