            aOrbiterB = RotL64((aOrbiterB * 0xBB8E50E8663BA215ULL), 47U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterC) + 0x27D146BCDE755F9BULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterE) ^ 0x226E57A470B2B870ULL;
            aOrbiterK = RotL64((aOrbiterK * 0xCF3E47AF88E0D8C7ULL), 39U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterB) + 0x122B3992A8E6A193ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterF) ^ 0x886627148E235AF2ULL;
            aOrbiterE = RotL64((aOrbiterE * 0xB174DC37E887478FULL), 27U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterA) + 0x824E8E7C1EDDB682ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterD) ^ 0xBA8D5570EE1836B1ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x0B3F27A0873BEA53ULL), 5U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterF) + 0x5088E34AB8BDF2EAULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterH) ^ 0xF232C0E22EBCB015ULL;
            aOrbiterG = RotL64((aOrbiterG * 0x509DE5B35ADC0FC9ULL), 57U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterE) + 0x8E127A18190383E7ULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterG) ^ 0x71A17DAF60901DB9ULL) ^ aPhaseDOrbiterUpdateSaltF[(((31U - aIndex) + 3U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0xB9D3B293159C742DULL), 43U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterK) + 0x10BF9393E74F4F72ULL) + aPhaseDOrbiterUpdateSaltD[(((31U - aIndex) + 13U)) & S_SALT1];
            aOrbiterF = ((aOrbiterF ^ aOrbiterA) ^ 0xA02F9F6B618EE8B2ULL) ^ aPhaseDOrbiterUpdateSaltC[((aIndex + 18U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0xDCBE75A5F4BBDF13ULL), 19U);
