            //
            aOrbiterF = (((aWandererK + RotL64(aIngress, 5U)) + RotL64(aCarry, 47U)) + 0xBA4BD91151814404ULL) + aPhaseGOrbiterAssignSaltF[((aIndex + 4U)) & S_SALT1];
            aOrbiterC = (aWandererA + RotL64(aPrevious, 57U)) + 0xB87820E2711FC8B6ULL;
            aOrbiterI = (aWandererC + RotL64(aCross, 46U)) + 0x9FBF33ACBA93DC7DULL;
            aOrbiterJ = (aWandererE + RotL64(aScatter, 53U)) + 0x31717839A1B16132ULL;
            aOrbiterG = ((aWandererJ + RotL64(aIngress, 27U)) + 0xF8BF16DD267814A5ULL) + aPhaseGOrbiterAssignSaltA[((aIndex + 17U)) & S_SALT1];
            aOrbiterA = ((aWandererI + RotL64(aPrevious, 51U)) + RotL64(aCarry, 21U)) + 0xF50746B6D77A1487ULL;
            aOrbiterB = (aWandererD + RotL64(aCross, 3U)) + 0x56CB4E7F08C12F25ULL;
