            aOrbiterE = ((aWandererB + RotL64(aScatter, 21U)) + RotL64(aCarry, 43U)) + 0x83B35EC2B5FB774FULL;
            aOrbiterH = (aWandererF + RotL64(aCross, 48U)) + 0xE157B6F158468239ULL;
            //
