            aOrbiterF = RotL64((aOrbiterF * 0x143A1BA6B58EF7F5ULL), 19U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 0x3173C22EBF8EAF33ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterB) ^ 0x7650B530E0AD33D8ULL;
